package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnCommentUpdateProxy struct {
	automation.UnimplementedOnCommentUpdateServer
	client automation.OnCommentUpdateClient
}

func init() {
	proxyutil.Register(&automation.OnCommentUpdate_ServiceDesc, NewOnCommentUpdateProxy)
}
func NewOnCommentUpdateProxy(cc grpc.ClientConnInterface) automation.OnCommentUpdateServer {
	return &OnCommentUpdateProxy{client: automation.NewOnCommentUpdateClient(cc)}
}
func (p *OnCommentUpdateProxy) OnCommentUpdate(ctx context.Context, in *events.CommentUpdate) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.CommentUpdate, automation.HandlerResult](p.client.OnCommentUpdate)(ctx, in)
}
